import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "find_arbitrage_opportunities",
    args: { category: "politics", limit: 25 }
  });

  const arbitrageOpportunities = Array.isArray(result?.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result?.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const filteredArbitrage = arbitrageOpportunities
    .filter((op) => typeof op?.totalCost === "number" && op.totalCost < 0.995)
    .map((op) => ({
      market: op?.market,
      url: op?.url,
      totalCost: op?.totalCost,
      edgePercent: op?.edgePercent,
      buyYesAt: op?.buyYesAt,
      buyNoAt: op?.buyNoAt,
      liquidity: op?.liquidity,
      potentialEdge: op?.potentialEdge,
      conditionId: op?.conditionId
    }));

  const topTwoWideSpreads = wideSpreadMarkets
    .slice()
    .sort((a, b) => (b?.spread ?? -Infinity) - (a?.spread ?? -Infinity))
    .slice(0, 2)
    .map((m) => ({
      market: m?.market,
      spread: m?.spread,
      midPrice: m?.midPrice,
      url: m?.url
    }));

  return {
    fetchedAt: result?.fetchedAt,
    summary: result?.summary,
    method: result?.methodology,
    arbitrageCount: filteredArbitrage.length,
    arbitrageOpportunities: filteredArbitrage,
    wideSpreadMarkets: topTwoWideSpreads
  };
}

